let P=[];
let __favIds=new Set();
let __favOrder=[];
function dbToBrowse(r){const cur=r.currency||{symbol:'£',code:'GBP'};cur.symbol=__wrapArSym(cur.symbol,cur.code);const photo=(r.photos&&r.photos[0])||null;const e=photo?`<img src="${photo}" alt="" style="width:100%;height:100%;object-fit:cover;border-radius:inherit"/>`:(cur.flag||'📦');const d={};Object.entries(r.delivery||{}).forEach(([code,z])=>{d[code]={cities:[],c:{},shipping:0,delivery:0};Object.entries(z.cities||{}).forEach(([city,v])=>{d[code].c[city]={s:Number(v.shipping)||0,d:Number(v.delivery)||0};d[code].cities.push(city);d[code].shipping=Number(v.shipping)||0;d[code].delivery=Number(v.delivery)||0;});});return{id:r.id,bid:r.business_id,biz:r.biz_name||'',bizPhone:r.biz_phone||'',e,ph:r.photos||[],n:r.name,cat:r.category||'',code:r.code||'',desc:r.description||'',pr:Number(r.price)||0,cur:{s:cur.symbol||'£',code:cur.code||'GBP'},pct:Number(r.comm_pct)||0,platformFee:Number(r.platform_fee)||0,q:Number(r.qty)||0,sv:__favIds.has(r.id),sz:r.sizes||[],cl:r.colors||[],d};}
async function loadBrowse(){if(!window.LateenAPI)return;try{const api=window.LateenAPI;if(api.listFavoriteIdsOrdered){__favOrder=await api.listFavoriteIdsOrdered();__favIds=new Set(__favOrder);}else{__favIds=await api.listFavoriteIds();__favOrder=[...__favIds];}const rows=await api.listBrowse();P=rows.map(dbToBrowse);rebuildProductsMap();if(typeof go==='function')go();if(typeof renderSaved==='function')renderSaved();}catch(e){console.error('[Lateen] loadBrowse',e);}}
function favSortedProducts(){const idx=new Map(__favOrder.map((id,i)=>[id,i]));return P.filter(p=>p.sv).sort((a,b)=>{const ai=idx.has(a.id)?idx.get(a.id):1e9;const bi=idx.has(b.id)?idx.get(b.id):1e9;return ai-bi;});}
const pctHtml=v=>`<span class="pct-inline" dir="ltr" data-no-i18n>${v}%</span>`;
function rebuildProductsMap(){PRODUCTS={};const sel=document.getElementById('f-product');const cur=sel?sel.value:'';const favs=favSortedProducts();if(sel){sel.innerHTML='<option value=""></option>'+favs.map(p=>`<option value="${p.id}">${p.n} · ${__money(p.pr,p.cur.s,p.cur.code)}</option>`).join('');if(cur&&P.find(p=>p.id===cur))sel.value=cur;}P.forEach(p=>{const delivery={};Object.entries(p.d).forEach(([code,z])=>{delivery[code]={cities:z.cities||Object.keys(z.c||{}),shipping:z.shipping||0,delivery:z.delivery||0,_per:z.c||{}};});PRODUCTS[p.id]={id:p.id,bid:p.bid,name:p.n,price:p.pr,pct:p.pct/100,sizes:p.sz,colors:p.cl,biz:p.biz,bizPhone:p.bizPhone,sym:p.cur.s,currency:{symbol:p.cur.s,code:p.cur.code},delivery};});if(typeof syncProductPickerLabel==='function')syncProductPickerLabel();}
function __pkT(){const ar=__ar();return {sel:ar?'اختر منتجاً محفوظاً':'Select a saved product',title:ar?'المنتجات المحفوظة':'Saved products',search:ar?'ابحث في المنتجات المحفوظة…':'Search saved products…',commission:ar?'عمولة':'commission',noMatch:ar?'لا توجد نتائج مطابقة.':'No matches.',empty:ar?'لا توجد منتجات محفوظة بعد. اضغط على القلب في صفحة التصفح لحفظ منتج.':'No saved products yet. Tap the heart on a product in Browse to save it.',fieldLabel:ar?'اختر من منتجاتك المحفوظة':'Choose from your saved products',section:ar?'المنتج':'Product'};}
function syncProductPickerLabel(){const t=__pkT();const fl=document.getElementById('prod-field-label');if(fl)fl.textContent=t.fieldLabel;const sl=document.getElementById('prod-section-label');if(sl)sl.textContent=t.section;const sel=document.getElementById('f-product');if(!sel)return;const id=sel.value;const p=id?P.find(x=>x.id===id):null;const lbl=document.getElementById('prod-picker-label');const sub=document.getElementById('prod-picker-sub');const thumb=document.getElementById('prod-picker-thumb');if(!lbl||!sub||!thumb)return;if(!p){lbl.textContent=t.sel;lbl.style.color='var(--color-text-secondary)';sub.style.display='none';thumb.innerHTML='📦';}else{lbl.textContent=p.n;lbl.style.color='var(--color-text-primary)';sub.style.display='block';sub.innerHTML=`${__money(p.pr,p.cur.s,p.cur.code)} · ${pctHtml(p.pct)} ${t.commission}${p.biz?' · '+p.biz:''}`;thumb.innerHTML=p.e;}}
function openProductPicker(){const ov=document.getElementById('prod-picker-overlay');if(!ov)return;const t=__pkT();const ttl=document.getElementById('prod-picker-title');if(ttl)ttl.textContent=t.title;const s=document.getElementById('prod-picker-search');if(s){s.value='';s.setAttribute('placeholder',t.search);s.blur();}ov.classList.add('open');try{document.body.style.overflow='hidden';document.documentElement.style.overflow='hidden';}catch(e){}renderProductPicker('');__bindProductPickerList();}
function closeProductPicker(){const ov=document.getElementById('prod-picker-overlay');if(!ov)return;const s=document.getElementById('prod-picker-search');if(s)s.blur();ov.classList.remove('open');try{document.body.style.overflow='';document.documentElement.style.overflow='';}catch(e){}}
function renderProductPicker(q){const list=document.getElementById('prod-picker-list');if(!list)return;const t=__pkT();const favs=favSortedProducts();const qq=(q||'').trim().toLowerCase();const filtered=qq?favs.filter(p=>p.n.toLowerCase().includes(qq)||(p.cat||'').toLowerCase().includes(qq)||(p.biz||'').toLowerCase().includes(qq)||(p.code||'').toLowerCase().includes(qq)):favs;if(!filtered.length){list.innerHTML=`<div style="padding:30px 12px;text-align:center;color:var(--color-text-secondary);font-size:13px;line-height:1.5;">${favs.length?t.noMatch:t.empty}</div>`;return;}list.innerHTML=filtered.map(p=>`<button type="button" data-pid="${p.id}" class="product-card-saved" style="cursor:pointer;text-align:start;font-family:var(--font-sans);width:100%;-webkit-tap-highlight-color:transparent;touch-action:manipulation;"><div class="product-thumb" style="pointer-events:none;">${p.e}</div><div style="flex:1;min-width:0;pointer-events:none;"><div class="product-name">${p.n}</div><div class="product-meta">${__money(p.pr,p.cur.s,p.cur.code)} · ${pctHtml(p.pct)} ${t.commission}</div></div></button>`).join('');}
function __bindProductPickerList(){const list=document.getElementById('prod-picker-list');if(!list||list.__bound)return;list.__bound=true;const h=(e)=>{const btn=e.target&&e.target.closest&&e.target.closest('button[data-pid]');if(!btn)return;e.preventDefault();e.stopPropagation();const pid=btn.getAttribute('data-pid');if(pid)pickProduct(pid);};list.addEventListener('click',h);list.addEventListener('touchend',h,{passive:false});}
function pickProduct(id){const sel=document.getElementById('f-product');if(!sel)return;if(!Array.from(sel.options).some(o=>o.value===id)){const p=P.find(x=>x.id===id);if(p){const opt=document.createElement('option');opt.value=p.id;opt.textContent=`${p.n} · ${__money(p.pr,p.cur.s,p.cur.code)}`;sel.appendChild(opt);}}sel.value=id;closeProductPicker();syncProductPickerLabel();if(typeof onProductChange==='function')onProductChange();if(typeof persistOpenDraft==='function')setTimeout(persistOpenDraft,0);}
