function onCam(i){if(!i.files.length)return;document.getElementById('cam').classList.add('open');document.getElementById('clb').textContent='Analysing image…';document.getElementById('cem').textContent='';document.getElementById('cnm').textContent='';setTimeout(()=>{const m=P[Math.floor(Math.random()*P.length)];document.getElementById('cem').textContent=m.e;document.getElementById('cnm').textContent='Found: '+m.n;document.getElementById('clb').textContent='Tap to open';document.getElementById('cnm').onclick=()=>{closeCam();openD(m.id);};},1400);i.value='';}
function closeCam(){document.getElementById('cam').classList.remove('open');}
function renderSaved(){const saved=P.filter(p=>p.sv);const c=document.getElementById('saved-list');const t=__pkT();if(!c)return;if(!saved.length){c.innerHTML=`<div class="saved-empty"><div class="saved-empty-icon">🤍</div>No saved products yet.<br>Browse and tap the heart to save products you want to market.</div>`;return;}c.innerHTML=`<div class="products-list">${saved.map(p=>`<div class="product-card-saved" onclick="openD('${p.id}')" style="cursor:pointer;-webkit-tap-highlight-color:transparent;"><div class="product-thumb" style="pointer-events:none">${p.e}</div><div style="flex:1;pointer-events:none"><div class="product-name">${p.n}</div><div class="product-meta">${__money(p.pr,p.cur.s,p.cur.code)} · ${pctHtml(p.pct)} ${t.commission}</div></div><button class="save-btn" onclick="event.stopPropagation();sv('${p.id}')"><svg width="16" height="16" viewBox="0 0 24 24" fill="#E24B4A" stroke="#E24B4A" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/></svg></button></div>`).join('')}</div>`;}

/* ── Orders ── */
const PLATFORM_FEE_RATE=0.05;
let PRODUCTS={};
const COUNTRY_NAMES={NG:'Nigeria',GH:'Ghana',EG:'Egypt',KE:'Kenya',ZA:'South Africa',LY:'Libya'};
let currentProduct=null,currentDelivery=null,qty=1,selectedSize='',selectedColor='',depositConfirmed=null,hasReceipt=false,receiptUrl='',orders=[],editingId=null;
const fmt=n=>__money(n,'£','GBP');
const fmtS=(sym,n,code)=>__money(n,sym,code);
const fmtO=(o,n)=>__money(n,o&&o._sym,o&&o._curCode);
const genCode=()=>'ORD-'+Math.random().toString(36).substr(2,6).toUpperCase();
const today2=()=>{const d=new Date();return d.getDate()+'/'+(d.getMonth()+1)+'/'+d.getFullYear();};
function calcFee(prod,q){const commPerUnit=parseFloat((prod.price*prod.pct).toFixed(2));const platformPerUnit=parseFloat((prod.price*PLATFORM_FEE_RATE).toFixed(2));const feePerUnit=parseFloat((commPerUnit+platformPerUnit).toFixed(2));const totalFee=parseFloat((feePerUnit*q).toFixed(2));return{commPerUnit,platformPerUnit,feePerUnit,totalFee};}
function updateFeeCard(){if(!currentProduct)return;const{commPerUnit,platformPerUnit,feePerUnit,totalFee}=calcFee(currentProduct,qty);const sym=currentProduct.currency&&currentProduct.currency.symbol;const code=currentProduct.currency&&currentProduct.currency.code;const money=n=>__money(n,sym,code);document.getElementById('fee-total').textContent=money(totalFee);document.getElementById('fee-qty-note').textContent=qty>1?money(feePerUnit)+' per unit × '+qty:'per unit';document.getElementById('fee-commission').textContent=money(commPerUnit);document.getElementById('fee-platform').textContent=money(platformPerUnit);}
function onProductChange(){const key=document.getElementById('f-product').value;selectedSize='';selectedColor='';qty=1;document.getElementById('qty-display').textContent='1';document.getElementById('f-country').value='';document.getElementById('f-city').value='';document.getElementById('f-city').disabled=true;document.getElementById('f-city').innerHTML='<option value="">— Select country first —</option>';['prod-info','biz-costs','fee-card'].forEach(id=>document.getElementById(id).style.display='none');['size-group','color-group','qty-row'].forEach(id=>document.getElementById(id).style.display='none');document.getElementById('location-fields').style.display='none';document.getElementById('delivery-section-label').style.display='none';document.getElementById('address-field').style.display='none';document.getElementById('no-delivery-note').style.display='none';document.getElementById('country-hint').textContent='';document.getElementById('city-hint').textContent='';if(!key){currentProduct=null;return;}currentProduct=PRODUCTS[key];const p=currentProduct;const money=n=>__money(n,p.currency&&p.currency.symbol,p.currency&&p.currency.code);document.getElementById('pi-price').innerHTML=__moneyH(p.price,p.currency&&p.currency.symbol,p.currency&&p.currency.code);document.getElementById('pi-pct').textContent=Math.round(p.pct*100)+'%';document.getElementById('pi-earn').innerHTML=__moneyH(p.price*p.pct,p.currency&&p.currency.symbol,p.currency&&p.currency.code);document.getElementById('prod-info').style.display='block';document.getElementById('fee-card').style.display='block';document.getElementById('qty-row').style.display='flex';if(p.sizes.length){document.getElementById('size-group').style.display='block';document.getElementById('size-chips').innerHTML=p.sizes.map(s=>`<div class="vchip" onclick="selectVariant('size','${s}',this)">${s}</div>`).join('');}if(p.colors.length){document.getElementById('color-group').style.display='block';document.getElementById('color-chips').innerHTML=p.colors.map(c=>`<div class="vchip" onclick="selectVariant('color','${c}',this)">${c}</div>`).join('');}const avail=Object.keys(p.delivery);const cs=document.getElementById('f-country');cs.innerHTML='<option value="">— Select country —</option>';avail.forEach(code=>{const o=document.createElement('option');o.value=code;o.textContent=COUNTRY_NAMES[code]||code;cs.appendChild(o);});document.getElementById('delivery-section-label').style.display='block';document.getElementById('location-fields').style.display='grid';document.getElementById('country-hint').textContent=avail.length+' countries available for this product';updateFeeCard();}
function onCountryChange(){const cc=document.getElementById('f-country').value;const cs=document.getElementById('f-city');const noteEl=document.getElementById('no-delivery-note');const bizCosts=document.getElementById('biz-costs');document.getElementById('city-hint').textContent='';cs.innerHTML='<option value="">— Select city —</option>';cs.disabled=true;bizCosts.style.display='none';noteEl.style.display='none';document.getElementById('address-field').style.display='none';currentDelivery=null;if(!cc||!currentProduct)return;const di=currentProduct.delivery[cc];if(!di){noteEl.textContent='This product is not available for delivery to '+(COUNTRY_NAMES[cc]||cc)+'. Please choose a different country.';noteEl.style.display='block';return;}di.cities.forEach(c=>{const o=document.createElement('option');o.value=c;o.textContent=c;cs.appendChild(o);});cs.disabled=false;document.getElementById('city-hint').textContent=di.cities.length+' cities available';}
function onCityChange(){const city=document.getElementById('f-city').value;const cc=document.getElementById('f-country').value;if(!city||!cc||!currentProduct)return;const di=currentProduct.delivery[cc];if(!di)return;const per=(di._per&&di._per[city])?{shipping:di._per[city].s,delivery:di._per[city].d}:{shipping:di.shipping,delivery:di.delivery};currentDelivery={...di,...per,city,country:COUNTRY_NAMES[cc]||cc,countryCode:cc};const money=n=>__money(n,currentProduct.currency&&currentProduct.currency.symbol,currentProduct.currency&&currentProduct.currency.code);document.getElementById('bc-shipping').textContent=money(per.shipping);document.getElementById('bc-delivery').textContent=money(per.delivery);document.getElementById('bc-note').textContent='For '+city+', '+(COUNTRY_NAMES[cc]||cc)+' · set by business owner';document.getElementById('biz-costs').style.display='block';document.getElementById('address-field').style.display='block';updateSubmitState();if(typeof syncProductPickerLabel==='function')syncProductPickerLabel();}
function changeQty(d){qty=Math.max(1,qty+d);document.getElementById('qty-display').textContent=qty;updateFeeCard();persistOpenDraft();}
function selectVariant(type,val,el){const g=type==='size'?'size-chips':'color-chips';document.querySelectorAll('#'+g+' .vchip').forEach(c=>c.classList.remove('selected'));el.classList.add('selected');if(type==='size')selectedSize=val;else selectedColor=val;persistOpenDraft();}
function triggerUpload(){openReceiptPicker();}
function openReceiptPicker(){const ov=document.getElementById('receipt-picker-overlay');if(ov){ov.classList.add('open');try{document.body.style.overflow='hidden';}catch(e){}}}
function closeReceiptPicker(){const ov=document.getElementById('receipt-picker-overlay');if(ov){ov.classList.remove('open');try{document.body.style.overflow='';}catch(e){}}}
function pickReceipt(src){closeReceiptPicker();const map={camera:'file-input-camera',gallery:'file-input-gallery',files:'file-input-files'};const el=document.getElementById(map[src]||'file-input');if(el){el.value='';el.click();}}
async function onFileUpload(input){if(!input.files.length)return;const file=input.files[0];const box=document.getElementById('upload-box');const lbl=document.getElementById('upload-label');lbl.classList.remove('done','err');box.classList.remove('has-file','error');box.classList.add('uploading');lbl.innerHTML='<span class="upload-spinner"></span>Uploading '+file.name+'…';if(!window.LateenAPI||!window.LateenAPI.uploadReceipt){box.classList.remove('uploading');box.classList.add('error');lbl.classList.add('err');lbl.textContent='Upload service not ready — refresh and try again';hasReceipt=false;receiptUrl='';input.value='';updateSubmitState();return;}try{receiptUrl=await window.LateenAPI.uploadReceipt(file);hasReceipt=true;box.classList.remove('uploading');box.classList.add('has-file');lbl.classList.add('done');lbl.textContent='✓ Receipt ready · '+file.name;persistOpenDraft();updateSubmitState();}catch(e){console.error('[Lateen] uploadReceipt',e);box.classList.remove('uploading');box.classList.add('error');lbl.classList.add('err');lbl.textContent='Upload failed — tap to try again ('+(e.message||e)+')';hasReceipt=false;receiptUrl='';input.value='';updateSubmitState();}}
