function updateSubmitState(){const btn=document.getElementById('submit-btn');if(!btn)return;btn.disabled=false;btn.style.opacity='1';btn.style.cursor='pointer';if(hasReceipt){btn.textContent='Send Order to Business Owner';btn.style.background='#2dbd8f';btn.style.color='#fff';btn.title='Receipt will go to admin for verification, then forwarded to the business owner.';}else{btn.textContent=editingId?'Save changes (Draft)':'Save as Draft';btn.style.background='#f0eeeb';btn.style.color='#0D0D0D';btn.title='Saved locally. Upload a receipt to send for verification.';}}
